select *
from batch.outbox_event
where 1 = 1

    and tenant_id = #{tenantId}

  and publish_status in (#{pendingStatus1}, #{pendingStatus2})
  and (next_publish_at is null or next_publish_at <= current_timestamp)

    and (hashtext(tenant_id) & 2147483647) % #{shardTotal} = #{shardIndex}


    and aggregate_type = #{aggregateType}


    and publish_status = #{publishStatus}

order by id asc

    limit #{batchSize}

